const [item] = items;
const headers = item.json.headers && typeof item.json.headers === 'object' ? item.json.headers : {};
const normalizedHeaders = Object.fromEntries(Object.entries(headers).map(([key, value]) => [String(key).toLowerCase(), value]));
const expectedSecret = $env.N8N_WEBHOOK_SECRET;
const providedSecret = normalizedHeaders['x-n8n-webhook-secret'];
if (!expectedSecret) {
  throw new Error('N8N_WEBHOOK_SECRET is not configured');
}
if (String(providedSecret ?? '') !== String(expectedSecret)) {
  throw new Error('invalid webhook secret');
}
return items;

const [item] = items;
const payload = item.json.body ?? item.json;
if (!payload.query) {
  throw new Error('retrieval requires query text');
}
return [{ json: {
  query: String(payload.query),
  conversationId: payload.conversationId ? String(payload.conversationId) : null,
  documentIds: Array.isArray(payload.documentIds) ? payload.documentIds.map((value) => String(value)) : [],
  topK: Number.isFinite(Number(payload.topK)) ? Math.max(1, Math.min(20, Number(payload.topK))) : 5,
  requestId: payload.requestId ? String(payload.requestId) : null,
} }];

const embedding = items[0]?.json?.data?.[0]?.embedding;
if (!Array.isArray(embedding) || embedding.length === 0) {
  throw new Error('embedding response did not include a query vector');
}
const input = $('Normalize Query').first().json;
const filter = input.documentIds.length === 0
  ? undefined
  : { must: [{ key: 'documentId', match: { any: input.documentIds } }] };
return [{ json: {
  query: input.query,
  conversationId: input.conversationId,
  documentIds: input.documentIds,
  topK: input.topK,
  requestId: input.requestId,
  searchBody: {
    vector: embedding,
    limit: input.topK,
    with_payload: true,
    score_threshold: 0,
    filter,
  },
} }];

const request = $('Build Search Body').first().json;
const response = items[0]?.json;
const results = Array.isArray(response?.result) ? response.result : [];
return [{ json: {
  query: request.query,
  conversationId: request.conversationId,
  documentIds: request.documentIds,
  topK: request.topK,
  requestId: request.requestId,
  chunks: results.map((match, index) => ({
    id: String(match.id ?? `${index}`),
    documentId: String(match.payload?.documentId ?? ''),
    documentName: String(match.payload?.documentName ?? match.payload?.fileName ?? 'Unknown document'),
    chunkIndex: Number(match.payload?.chunkIndex ?? 0),
    content: String(match.payload?.content ?? ''),
    score: Number(match.score ?? 0),
    metadata: {
      tokenCount: match.payload?.tokenCount ?? null,
      source: 'qdrant',
    },
  })),
} }];
